import { create } from 'zustand';
import AsyncStorage from '@react-native-async-storage/async-storage';

interface ApiSettingsState {
  geminiApiKey: string;
  setGeminiApiKey: (key: string) => void;
  loadApiSettings: () => Promise<void>;
  saveApiSettings: () => Promise<void>;
}

const STORAGE_KEY = '@petpal:api';

export const useApiStore = create<ApiSettingsState>((set, get) => ({
  geminiApiKey: '',

  setGeminiApiKey: (key: string) => {
    set({ geminiApiKey: key });
    get().saveApiSettings();
  },

  loadApiSettings: async () => {
    try {
      const data = await AsyncStorage.getItem(STORAGE_KEY);
      if (data) {
        const settings = JSON.parse(data);
        set({ geminiApiKey: settings.geminiApiKey || '' });
      }
    } catch (error) {
      console.error('Failed to load API settings:', error);
    }
  },

  saveApiSettings: async () => {
    try {
      const { geminiApiKey } = get();
      await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify({ geminiApiKey }));
    } catch (error) {
      console.error('Failed to save API settings:', error);
    }
  },
}));
